1	type Input = { steps: Array<{ items: Array<{ type: string }> }> };
2	
3	const PROCESSING_FEE = 5;
4	
5	export function runScenario(input: unknown): unknown {
6	  const { steps } = input as Input;
7	  const items = steps[0].items;
8	  const premium = computePremium(items);
9	  return { results: [{ premium }] };
10	}
11	
12	function computePremium(items: Array<{ type: string }>): number {
13	  if (items.length === 0) return PROCESSING_FEE;
14	  if (items[0].type === "staff") return 93;
15	  return 71;
16	}
